// Dados do PR
const prData = $('Calcular métricas do PR').first().json;
const prAuthor = prData.pr_author || '';

// Buscar devs cadastrados
const devsResponse = $('Buscar Devs Cadastrados').first().json;
const devRows = devsResponse.items || [];

// Cruzar por GitHub username
let devName = prAuthor;
let devEmail = '';

for (const row of devRows) {
    const values = row.values || {};
    const githubUser = Object.values(values).find((v, i) => i === 1) || '';
    const nome = Object.values(values).find((v, i) => i === 0) || '';
    const email = Object.values(values).find((v, i) => i === 2) || '';

    if (typeof githubUser === 'string' && githubUser.toLowerCase() === prAuthor.toLowerCase()) {
        devName = nome;
        devEmail = email;
        break;
    }
}

return [{
    json: {
        ...prData,
        dev_name: devName,
        dev_email: devEmail,
        dev_identified: devName !== prAuthor
    }
}];

